    # --- LÓGICA MATEMÁTICA ---
    def obtener_datos(self):
        try:
            n1 = float(self.textEdit.toPlainText())
            t2 = self.textEdit_2.toPlainText()
            n2 = float(t2) if t2.strip() else 0.0
            return n1, n2
        except ValueError:
            self.label_4.setText("Error: Números")
            return None, None

    def conectar_botones(self):
        # Aritmética
        self.pushButton.clicked.connect(lambda: self.calcular("suma"))
        self.pushButton_2.clicked.connect(lambda: self.calcular("resta"))
        self.pushButton_3.clicked.connect(lambda: self.calcular("multi"))
        self.pushButton_12.clicked.connect(lambda: self.calcular("div"))
        # Trigonométricas
        self.pushButton_10.clicked.connect(lambda: self.calcular_trig("sen"))
        self.pushButton_11.clicked.connect(lambda: self.calcular_trig("cos"))
        self.pushButton_13.clicked.connect(lambda: self.calcular_trig("tan"))
        self.pushButton_14.clicked.connect(lambda: self.calcular_trig("sec"))
        self.pushButton_15.clicked.connect(lambda: self.calcular_trig("csc"))
        self.pushButton_16.clicked.connect(lambda: self.calcular_trig("cot"))

    def calcular(self, operacion):
        a, b = self.obtener_datos()
        if a is None: return
        
        if operacion == "suma": res = a + b
        elif operacion == "resta": res = a - b
        elif operacion == "multi": res = a * b
        elif operacion == "div":
            res = a / b if b != 0 else "Error Div/0"
        
        self.label_4.setText(str(res))
 
    def calcular_trig(self, operacion):
        a, _ = self.obtener_datos()
        if a is None: return
        
        # math usa radianes
        rad = math.radians(a)
        try:
            if operacion == "sen": res = math.sin(rad)
            elif operacion == "cos": res = math.cos(rad)
            elif operacion == "tan": res = math.tan(rad)
            elif operacion == "sec": res = 1 / math.cos(rad)
            elif operacion == "csc": res = 1 / math.sin(rad)
            elif operacion == "cot": res = 1 / math.tan(rad)
            self.label_4.setText(f"{res:.4f}")
        except ZeroDivisionError:
            self.label_4.setText("Error: Infinito")

